mapper.select:
SELECT DISTINCT c.*
FROM category c
INNER JOIN entry e ON e.account_id = c.id AND e.account_type = 'category'
INNER JOIN `transaction` t ON t.id = e.transaction_id AND t.is_deleted = 0
WHERE c.user_id = #{userId}

    AND c.type = #{type}

AND c.is_deleted = 0
ORDER BY t.created_at DESC
LIMIT #{limit}
